let hydrationCaptureProvider = null;
export function installHydrationCaptureProvider(provider) {
    hydrationCaptureProvider = provider;
}
export function createHydrationCapture() {
    return {
        hooks: new WeakMap(),
    };
}
export function getHydrationCapture() {
    return hydrationCaptureProvider?.() ?? null;
}
export function registerHydrationHook(chunk, hook) {
    const capture = getHydrationCapture();
    if (!capture)
        return;
    const hooks = capture.hooks.get(chunk);
    if (hooks) {
        hooks.push(hook);
    }
    else {
        capture.hooks.set(chunk, [hook]);
    }
}
export function adoptCapturedChunk(capture, chunk, map, visited = new WeakSet()) {
    if (visited.has(chunk))
        return;
    visited.add(chunk);
    const ref = chunk.ref;
    if (ref.f)
        ref.f = map.get(ref.f) ?? ref.f;
    if (ref.l)
        ref.l = map.get(ref.l) ?? ref.l;
    capture.hooks.get(chunk)?.forEach((hook) => hook(map, visited));
}
